// --- Split ---

(function () {
            const listEl = document.getElementById('memberWhitelistList');
            const statusMessageEl = document.getElementById('statusMessage');

            function escapeHtml(value) {
                return String(value ?? '')
                    .replace(/&/g, '&amp;')
                    .replace(/</g, '&lt;')
                    .replace(/>/g, '&gt;')
                    .replace(/"/g, '&quot;')
                    .replace(/'/g, '&#39;');
            }

            function renderWhitelistMembers(items) {
                if (!listEl) return;

                if (!Array.isArray(items) || items.length === 0) {
                    listEl.innerHTML = '<div class="member-empty">Chưa có thành viên nào trong danh sách whitelist.</div>';
                    return;
                }

                listEl.innerHTML = items.map((item) => {
                    const activated = Boolean(item?.activated);
                    const badgeClass = activated ? 'active' : 'inactive';
                    const badgeText = activated ? 'Đã kích hoạt' : 'Chưa kích hoạt';
                    return `
                        <div class="member-row">
                            <div class="member-name">${escapeHtml(item?.gamertag || 'Không rõ tên')}</div>
                            <span class="member-badge ${badgeClass}">${badgeText}</span>
                        </div>
                    `;
                }).join('');
            }

            async function loadWhitelistMembers() {
                if (!listEl) return;

                try {
                    const response = await fetch('/api/whitelist/list', { cache: 'no-store' });
                    const data = await response.json().catch(() => ({}));

                    if (!response.ok || !data.success) {
                        listEl.innerHTML = '<div class="member-empty">Không tải được danh sách whitelist lúc này.</div>';
                        return;
                    }

                    renderWhitelistMembers(data.items || []);
                } catch (_error) {
                    listEl.innerHTML = '<div class="member-empty">Không tải được danh sách whitelist lúc này.</div>';
                }
            }

            loadWhitelistMembers();

            if (statusMessageEl && typeof MutationObserver !== 'undefined') {
                const observer = new MutationObserver(() => {
                    const message = String(statusMessageEl.textContent || '').toLowerCase();
                    if (message.includes('thành công') || message.includes('thanh cong')) {
                        window.setTimeout(loadWhitelistMembers, 800);
                    }
                });
                observer.observe(statusMessageEl, {
                    childList: true,
                    subtree: true,
                    characterData: true
                });
            }
        }());